const Chart = memo(
  function Chart({ data, viewport, theme }: ChartProps) {
    // expensive render
    return <canvas />;
  },
  (prev, next) => {
    // Only re-render if data.id changes or viewport bounds change
    // Ignore unrelated changes to data or theme details
    return prev.data.id === next.data.id
      && prev.viewport.x === next.viewport.x
      && prev.viewport.y === next.viewport.y
      && prev.viewport.zoom === next.viewport.zoom
      && prev.theme === next.theme;
  }
);

