function backoffMs(attempt: number): number {
  const base = Math.min(30_000, 1000 * Math.pow(2, attempt));
  const jitter = Math.random() * base * 0.3;  // 30% jitter
  return base + jitter;
}

async function pollWithBackoff<T>(fn: () => Promise<T>): Promise<T> {
  let attempt = 0;
  while (true) {
    try {
      return await fn();
    } catch {
      await new Promise(r => setTimeout(r, backoffMs(attempt)));
      attempt++;
    }
  }
}

