import * as Sentry from '@sentry/react';

const seen = new Set<string>();

Sentry.init({
  dsn: '...',
  beforeSend(event, hint) {
    const error = hint.originalException as Error;
    const key = `${error?.name}-${error?.message?.slice(0, 100)}`;
    if (seen.has(key)) {
      return null;  // skip duplicate
    }
    seen.add(key);
    return event;
  }
});

import { useState } from 'react';

function DropdownMenu({ trigger, items }: { trigger: React.ReactNode; items: Item[] }) {
  const [open, setOpen] = useState(false);
  const isTouchDevice = matchMedia('(pointer: coarse)').matches;
  return (
    <div
      onMouseEnter={!isTouchDevice ? () => setOpen(true) : undefined}
      onMouseLeave={!isTouchDevice ? () => setOpen(false) : undefined}
    >
      <button onClick={() => setOpen(o => !o)} aria-expanded={open}>
        {trigger}
      </button>
      {open && <ul>{items.map(i => <li key={i.id}>{i.label}</li>)}</ul>}
    </div>
  );
}

async function apiFetch<T>(path: string, opts: RequestInit = {}): Promise<T> {
  const response = await fetch(path, {
    ...opts,
    credentials: 'include',
    headers: {
      'Content-Type': 'application/json',
      ...opts.headers
    }
  });
  if (response.status === 401) {
    window.location.href = '/login';
    throw new Error('Unauthorized');
  }
  if (!response.ok) {
    const data = await response.json().catch(() => ({}));
    throw new ApiError(data.message ?? response.statusText, response.status);
  }
  return response.json();
}

