// dialog.ts
let confirmFn: ((message: string) => Promise<boolean>) | null = null;

export function setConfirmFn(fn: typeof confirmFn) { confirmFn = fn; }
export function confirm(message: string): Promise<boolean> {
  if (!confirmFn) return Promise.resolve(window.confirm(message));
  return confirmFn(message);
}

// ConfirmProvider mounts at app root
function ConfirmProvider({ children }: { children: React.ReactNode }) {
  const [state, setState] = useState<{ message: string; resolve: (ok: boolean) => void } | null>(null);
  useEffect(() => {
    setConfirmFn((message) => new Promise<boolean>((resolve) => setState({ message, resolve })));
  }, []);
  return (
    <>
      {children}
      {state && (
        <Dialog open onClose={() => { state.resolve(false); setState(null); }}>
          <p>{state.message}</p>
          <button onClick={() => { state.resolve(false); setState(null); }}>Cancel</button>
          <button onClick={() => { state.resolve(true); setState(null); }}>OK</button>
        </Dialog>
      )}
    </>
  );
}

