import { Controller, useFormContext } from 'react-hook-form';
import { ComboBox, Item } from 'react-aria-components';

function FormCombobox<TOptions>({ name, label, options }: { name: string; label: string; options: { id: string; label: string }[] }) {
  const { control } = useFormContext();
  return (
    <Controller
      control={control}
      name={name}
      render={({ field }) => (
        <ComboBox aria-label={label} selectedKey={field.value} onSelectionChange={field.onChange}>
          {options.map(o => <Item key={o.id} id={o.id}>{o.label}</Item>)}
        </ComboBox>
      )}
    />
  );
}

